import os, json
from cryptography.fernet import Fernet
from pathlib import Path

SECRETS_ENC = Path('secrets.enc')
KEY_ENV = 'AVZ_SECRET_KEY'

class SecretsManager:
    def __init__(self):
        self.key = os.environ.get(KEY_ENV)
        if not self.key:
            self.key = Fernet.generate_key().decode()
            os.environ[KEY_ENV] = self.key
            print(f'[!] New encryption key generated: {self.key}')
        self.cipher = Fernet(self.key.encode())

    def load(self):
        if SECRETS_ENC.exists():
            return json.loads(self.cipher.decrypt(SECRETS_ENC.read_bytes()))
        return {}

    def save(self, data):
        SECRETS_ENC.write_bytes(self.cipher.encrypt(json.dumps(data).encode()))

    def get(self, key, default=None):
        return self.load().get(key, default)

