import subprocess, sys
from pathlib import Path
from utils.secrets_manager import SecretsManager
from utils.logger import logger

ROOT = Path(__file__).parent

def check_git():
    try:
        subprocess.check_call(['git', 'rev-parse', '--is-inside-work-tree'], cwd=ROOT)
        print('[+] Git repository found')
    except:
        print('[-] Not a git repository')

def check_github_push():
    secrets = SecretsManager()
    token = secrets.get('github_token')
    if not token:
        print('[-] GitHub token not set')
        return
    import requests
    r = requests.get('https://api.github.com/user', headers={'Authorization': f'token {token}'})
    if r.status_code == 200:
        print('[+] GitHub token is valid')
    else:
        print(f'[-] GitHub token invalid: {r.status_code}')

def check_dependencies():
    deps = ['paramiko', 'cryptography', 'requests']
    for d in deps:
        try:
            __import__(d)
            print(f'[+] {d} installed')
        except ImportError:
            print(f'[-] {d} MISSING — run pip install -r requirements.txt')

def check_manifest():
    if (ROOT / 'manifest.json').exists():
        print('[+] manifest.json present')
    else:
        print('[-] No manifest.json')

if __name__ == '__main__':
    print('=== AVZ Diagnostic ===')
    check_git()
    check_github_push()
    check_dependencies()
    check_manifest()
    print('Review avz_debug.log for runtime issues')
